30	def cc_PointerType : CCType<"Pointer", "ptr"> {
31	  let summary = "A C++ pointer/reference type.";
32	  let description = [{
33	    The bridge can use this type to represent values that are addresses in
34	    memory. That includes declarations such as `T*` (pointer to T), `T&`
35	    (lvalue reference to T), and `T&&` (rvalue reference to T).
36	
37	    This is a more permissive type than the LLVMPointerType, which has
38	    restrictions on its element type that makes it harder to use at time.
39	    Ultimately, !cc.ptr types will become LLVM IR pointers.
40	  }];
