47	      return Base::get(elementType.getContext(), elementType);
48	    }]>,
49	    TypeBuilder<(ins), [{
50	      return $_get($_ctxt, mlir::NoneType::get($_ctxt));
51	    }]>
52	  ];
53	}
54	
55	//===----------------------------------------------------------------------===//
56	// StructType
57	//===----------------------------------------------------------------------===//
58	
59	def cc_StructType : CCType<"Struct", "struct",
60	    [DeclareTypeInterfaceMethods<DataLayoutTypeInterface>]> {
61	  let summary = "Primitive aggregate C/C++ type.";
62	  let description = [{
63	    A struct is first-class type for an aggregate tuple value composed of
64	    multiple ordered subvalues of any type. A value of type struct need not be
65	    a memory object like an array.
66	
67	    A subobject is indexed by position from `0` to `N-1`, where `N` is the
68	    number of members in the struct.
69	
70	    For portability between tools, a StructType may carry its size and alignment
71	    as part of the type. These values can come from the C++ front end. If they
72	    are not provided, the size of the struct will be deferred and LLVM will
73	    determine it.
74	  }];
75	
76	  let parameters = (ins
77	    "mlir::StringAttr":$name,
78	    ArrayRefParameter<"mlir::Type">:$members,
79	    "bool":$opaque,
80	    "bool":$packed,
81	    "std::uint64_t":$bitSize,
82	    "unsigned":$alignment
83	  );
