90	                 CArg<"bool", "true">:$isOpaque), [{
91	      return $_get($_ctxt, mlir::StringAttr::get($_ctxt, name),
92	                   llvm::ArrayRef<mlir::Type>{}, isOpaque, /*isPacked=*/false,
93	                   /*bitSize=*/0, /*alignment=*/0);
94	    }]>,
