103	                 CArg<"llvm::ArrayRef<mlir::Type>">:$members,
104	                 CArg<"std::uint64_t">:$size, CArg<"unsigned">:$align,
105	                 CArg<"bool", "false">:$isPacked), [{
106	      return $_get($_ctxt, mlir::StringAttr::get($_ctxt, name), members,
107	                   /*isOpaque=*/false, isPacked, size, align);
108	    }]>,
109	    TypeBuilder<(ins CArg<"llvm::ArrayRef<mlir::Type>">:$members,
110	                 CArg<"bool", "false">:$isPacked), [{
111	      return $_get($_ctxt, mlir::StringAttr{}, members, /*isOpaque=*/false,
112	                   isPacked, /*bitSize=*/0, /*alignment=*/0);
113	    }]>,
114	    TypeBuilder<(ins CArg<"llvm::ArrayRef<mlir::Type>">:$members,
115	                 CArg<"std::uint64_t">:$size, CArg<"unsigned">:$align,
116	                 CArg<"bool", "false">:$isPacked), [{
117	      return $_get($_ctxt, mlir::StringAttr{}, members, /*isOpaque=*/false,
118	                   isPacked, size, align);
119	    }]>
120	  ];
121	
122	  let extraClassDeclaration = [{
123	    // O(1)
124	    bool isEmpty() const { return getMembers().empty(); }
125	
126	    // O(n)
127	    std::size_t getNumMembers() const { return getMembers().size(); }
128	
129	    Type getMember(unsigned position) { return getMembers()[position]; }
130	  }];
131	}
