137	def cc_ArrayType : CCType<"Array", "array"> {
138	  let summary = "Primitive C-like, one-dimensional sequential type.";
139	  let description = [{
140	    A value in memory of type `!cc.array` is similar to a `!cc.pointer` but
141	    allows 0-based indexing into a sequence of values. A `!cc.pointer` by
142	    contrast points to a single object.
143	
144	    A value of type `!cc.array` should ordinarily be an object in memory. This
145	    is transitive in nature, so any aggregate that recursively has a member of
146	    `!cc.array` should itself reside in memory. More precisely, loading an array
147	    into a register is not portable.
148	
149	    See also the StdVectorType type as another aggregate sequence of values.
150	  }];
