178	def cc_CallableType : CCType<"Callable", "callable"> {
179	  let summary = "Proxy for a C++ callable instance in cc";
180	  let description = [{
181	    A kernel may be a template function that takes a callable as an argument.
182	    The type of these callable instances is this proxy callable type. The
183	    instantiated template instance will resolve the callable instance, and this
184	    resolved instance of the callable will be lowered in the specialized
185	    template function.
