213	
214	  let assemblyFormat = "`<` $signature `>`";
215	
216	  let builders = [
217	    TypeBuilderWithInferredContext<(ins "mlir::FunctionType":$signature), [{
218	      return Base::get(signature.getContext(), signature);
219	    }]>
220	  ];
