223	//===----------------------------------------------------------------------===//
224	// StdVectorType - implemented as a span
225	//===----------------------------------------------------------------------===//
226	
227	def cc_StdVectorType : CCType<"Stdvec", "stdvec", [],
228	    "cudaq::cc::SpanLikeType"> {
229	  let summary = "Proxy for a std::vector<T> in cc";
230	  let description = [{
231	    This captures a C++ std::vector<T> template type as an abstract CC
232	    type. The intention is to allow us to reason about std::vectors at the
233	    CC level before decomposing these into more refined data structures.
234	
235	    ```c++
236	    void foo(std::vector<int> vec) ...
237	    ```
238	    will be lowered from the AST to CC as
239	    ```mlir
240	    func.func @foo(%arg0 : !cc.stdvec<i32>) ...
241	    ```
242	    assuming `int` has a length of 32 bits for the target.
243	  }];
244	
245	  let parameters = (ins "mlir::Type":$elementType);
246	
247	  let assemblyFormat = "`<` qualified($elementType) `>`";
248	
249	  let genVerifyDecl = 1;
250	
251	  let builders = [
252	    TypeBuilderWithInferredContext<(ins "mlir::Type":$elementType), [{
253	      return Base::get(elementType.getContext(), elementType);
254	    }]>
255	  ];
256	}
