262	def cc_CharSpanType
263	    : CCType<"Charspan", "charspan", [], "cudaq::cc::SpanLikeType"> {
264	  let summary = "Proxy for a span over a std::string in cc";
265	  let description = [{
266	    This captures a C++ std::string(of char) type as an abstract CC type. The
267	    intention is to allow us to reason about std::string at the CC level before
268	    decomposing these into more refined data structures.
269	
270	    ```c++
271	    void foo(std::string aString)...
272	    ```
273	    will be lowered from the AST to CC as
274	    ```mlir
275	    func.func @foo(%arg0 : !cc.charspan)...
276	    ```
277	  }];
278	
279	  let extraClassDeclaration = [{
280	    mlir::IntegerType getElementType() const {
281	      return mlir::IntegerType::get(getContext(), 8);
282	    }
283	  }];
284	}
285	
286	//===----------------------------------------------------------------------===//
287	// MeasureHandleType - opaque, word-sized classical value
288	//===----------------------------------------------------------------------===//
289	
290	def cc_MeasureHandleType : CCType<"MeasureHandle", "measure_handle"> {
291	  let summary = "An opaque word-sized handle for a measurement event.";
292	  let description = [{
293	    The IR alias of the C++ `cudaq::measure_handle` class. Semantically an
294	    opaque, word-sized classical value (an `i64` payload) whose only meaningful
295	    consumer is `quake.discriminate`. The bridge emits this type so that
296	    verification passes can reject entry-point kernels that leak handles across
297	    the host-device boundary; a late lowering pass replaces it with `i64`
298	    before QIR emission.
299	
300	    ```mlir
301	      %mh = quake.mz %q name "mh" : (!quake.ref) -> !cc.measure_handle
302	      %b  = quake.discriminate %mh : (!cc.measure_handle) -> i1
303	    ```
304	  }];
305	}
306	
307	def IsSpanLikePred : CPred<"isa<cudaq::cc::SpanLikeType>($_self)">;
308	def SpanningType : Type<IsSpanLikePred, "dynamic length type">;
309	
310	def AnyStateInitLike : TypeConstraint<cc_PointerType.predicate,
311	                         "state initializer types">;
312	def AnyStateInitType : Type<AnyStateInitLike.predicate, "initial state type">;
313	
314	def IsStdvecTypePred : CPred<"::mlir::isa<::cudaq::cc::StdvecType>($_self)">;
315	
316	class StdvecOf<list<Type> allowedTypes> : Type<
317	    And<[IsStdvecTypePred, Concat<"[](::mlir::Type elementType) { return ",
318	      SubstLeaves<"$_self", "elementType", AnyTypeOf<allowedTypes>.predicate>,
319	        "; }(::mlir::cast<::cudaq::cc::StdvecType>($_self).getElementType())">]>,
320	    "stdvec of " # AnyTypeOf<allowedTypes>.summary # " values",
321	    "::cudaq::cc::StdvecType">;
322	
323	def IsPointerTypePred : CPred<"::mlir::isa<::cudaq::cc::PointerType>($_self)">;
324	
325	class PointerOf<list<Type> allowedTypes> : Type<
326	    And<[IsPointerTypePred, Concat<"[](::mlir::Type elementType) { return ",
327	      SubstLeaves<"$_self", "elementType", AnyTypeOf<allowedTypes>.predicate>,
328	        "; }(::mlir::cast<::cudaq::cc::PointerType>($_self).getElementType())">]>,
329	    "pointer of " # AnyTypeOf<allowedTypes>.summary # " values",
330	    "::cudaq::cc::PointerType">;
331	
332	#endif // CUDAQ_DIALECT_CC_TYPES_TD
