    [CallOpInterface, SymbolUserOpInterface]> {
  let summary = "Create a call to an llvm.func with variadic arguments.";
  let description = [{
    This operation lets us create a call to an LLVMIR FuncOp with variadic
    arguments without the restriction that all the arguments have to be
    converted to LLVMIR types first. These conversions are just code bloat and
    make the code harder to read.

    The use of LLVMIR dialect for varargs functions is required as MLIR's Func
    dialect does not support varargs calls.
  }];

  let arguments = (ins
    FlatSymbolRefAttr:$callee,
    Variadic<AnyType>:$args,
    OptionalAttr<DictArrayAttr>:$arg_attrs,
    OptionalAttr<DictArrayAttr>:$res_attrs
  );
  let results = (outs Variadic<AnyType>);

  let assemblyFormat = [{
    $callee `(` $args `)` `:` functional-type(operands, results) attr-dict
  }];

  let builders = [
    OpBuilder<(ins "mlir::TypeRange":$result, "mlir::FlatSymbolRefAttr":$callee,
        "mlir::ValueRange":$args), [{
      return build($_builder, $_state, result, callee, args, mlir::ArrayAttr{},
        mlir::ArrayAttr{});
    }]>,
    OpBuilder<(ins "mlir::TypeRange":$result, "mlir::StringRef":$callee,
        "mlir::ValueRange":$args), [{
      return build($_builder, $_state, result,
        mlir::FlatSymbolRefAttr::get($_builder.getContext(), callee), args,
        mlir::ArrayAttr{}, mlir::ArrayAttr{});
    }]>
  ];

  let extraClassDeclaration = [{
    operand_range getArgOperands() {
      return {arg_operand_begin(), arg_operand_end()};
    }

    operand_iterator arg_operand_begin() { return operand_begin(); }
    operand_iterator arg_operand_end() { return operand_end(); }

    mlir::MutableOperandRange getArgOperandsMutable() {
      return getArgsMutable();
    }

    /// Return the callee of this operation.
    mlir::CallInterfaceCallable getCallableForCallee() {
      return getCalleeAttr();
    }

